import React, { useState } from "react";

// ...suas constantes DENTES_SUP, DENTES_INF, ICONES e getSvgDente igual antes...

function OdontoQuadrado({ faces, onClickFace }) {
  // Cada face recebe fill/stroke conforme estado
  return (
    <svg width={36} height={36} viewBox="0 0 36 36">
      {/* Mesial */}
      <polygon
        id="mesial"
        points="3,3 12,3 12,33 3,33"
        fill={faces.mesial ? "#fbbf24" : "#f3f4f6"}
        stroke={faces.mesial ? "#ea580c" : "#999"}
        strokeWidth={1.2}
        onClick={() => onClickFace("mesial")}
        style={{cursor: "pointer"}}
      />
      {/* Distal */}
      <polygon
        id="distal"
        points="24,3 33,3 33,33 24,33"
        fill={faces.distal ? "#fbbf24" : "#f3f4f6"}
        stroke={faces.distal ? "#ea580c" : "#999"}
        strokeWidth={1.2}
        onClick={() => onClickFace("distal")}
        style={{cursor: "pointer"}}
      />
      {/* Vestibular */}
      <polygon
        id="vestibular"
        points="12,3 24,3 24,12 12,12"
        fill={faces.vestibular ? "#fbbf24" : "#f3f4f6"}
        stroke={faces.vestibular ? "#ea580c" : "#999"}
        strokeWidth={1.2}
        onClick={() => onClickFace("vestibular")}
        style={{cursor: "pointer"}}
      />
      {/* Palatina */}
      <polygon
        id="palatina"
        points="12,24 24,24 24,33 12,33"
        fill={faces.palatina ? "#fbbf24" : "#f3f4f6"}
        stroke={faces.palatina ? "#ea580c" : "#999"}
        strokeWidth={1.2}
        onClick={() => onClickFace("palatina")}
        style={{cursor: "pointer"}}
      />
      {/* Coroa/Oclusal */}
      <polygon
        id="coroa"
        points="12,12 24,12 24,24 12,24"
        fill={faces.coroa ? "#fbbf24" : "#f3f4f6"}
        stroke={faces.coroa ? "#ea580c" : "#999"}
        strokeWidth={1.2}
        onClick={() => onClickFace("coroa")}
        style={{cursor: "pointer"}}
      />
      {/* Borda do quadrado */}
      <rect x="3" y="3" width="30" height="30" fill="none" stroke="#bbb" strokeWidth={1.3} rx={6} ry={6}/>
    </svg>
  );
}

// -- MANTÉM O RESTANTE DO SEU CÓDIGO IGUAL --
// (Só substitua o OdontoQuadrado pelo JSX acima)

export default function OdontogramaDigital() {
  // ... state e funções igual seu código ...

  function renderDentes(arr) {
    return arr.map(num => (
      <div key={num} className="flex flex-col items-center mx-1" style={{ minWidth: 54 }}>
        {/* Checkbox azul */}
        <input
          type="checkbox"
          checked={!!dentesSelecionados[num]}
          onChange={() => toggleDenteCheckbox(num)}
          className="accent-blue-600 mb-1"
          style={{width: 18, height: 18}}
        />
        {/* Imagem SVG do dente conforme tratamento */}
        <img
          src={getSvgDente(num, tipoDente[num] || "normal")}
          alt={`Dente ${num}`}
          style={{
            width: 38,
            height: 44,
            objectFit: "contain",
            marginBottom: -8,
            filter: tipoDente[num] === "extracao" ? "grayscale(1)" : undefined,
            opacity: tipoDente[num] === "extracao" ? 0.5 : 1,
            transition: "0.2s"
          }}
        />
        {/* Quadrado anatômico CONTROLADO via React */}
        <OdontoQuadrado
          faces={facesSelecionadas[num] || {}}
          onClickFace={face => toggleFace(num, face)}
        />
        {/* Número FDI */}
        <span className="text-xs mt-1">{num}</span>
        {/* Ícones de tratamento */}
        {dentesSelecionados[num] && (
          <div className="flex gap-1 mt-1">
            {ICONES.map(ic => (
              <button
                key={ic.key}
                title={ic.label}
                onClick={() => handleIconeClick(num, ic.key)}
                className={`border rounded p-1 ${tipoDente[num] === ic.key ? "bg-blue-100" : "bg-white"} hover:bg-blue-50`}
                style={{ fontSize: 18, cursor: "pointer" }}
                type="button"
                tabIndex={0}
              >
                {ic.icon}
              </button>
            ))}
          </div>
        )}
      </div>
    ));
  }

  // ... restante igual ao seu código ...
}
